        "en-US": "Cancel Contrary Motion XYZ",
        "es-MX": "Cancelar movimiento contrario XYZ",
        "fr-FR": "Annuler le mouvement contraire XYZ",
        "ja-JP": "\u9006\u30E2\u30FC\u30B7\u30E7\u30F3XYZ\u3092\u30AD\u30E3\u30F3\u30BB\u30EB",
        "pt-BR": "Cancelar Deslocamento Contr\xE1rio XYZ",
        "th-TH": "\u0E22\u0E01\u0E40\u0E25\u0E34\u0E01\u0E01\u0E32\u0E23\u0E40\u0E04\u0E25\u0E37\u0E48\u0E2D\u0E19\u0E17\u0E35\u0E48\u0E41\u0E1A\u0E1A\u0E2A\u0E27\u0E19\u0E17\u0E32\u0E07 XYZ",
        "tr-TR": "XYZ Z\u0131t Hareketlerini \u0130ptal Et",
        "zh-CN": "\u53D6\u6D88\u76F8\u53CD\u8FD0\u52A8XYZ",
        "de-DE": "Cancel Contrary Motion XYZ",
