        "th-TH": "\u0E23\u0E27\u0E21\u0E01\u0E32\u0E23\u0E40\u0E04\u0E25\u0E37\u0E48\u0E2D\u0E19\u0E17\u0E35\u0E48\u0E41\u0E1A\u0E1A\u0E2A\u0E27\u0E19\u0E17\u0E32\u0E07",
