// src/compiler/functions/hsl.ts
astParsingFunctions.hsl = function(content) {
  let h = "$h";
  let s = "$s";
  let l = "$l";
  let a = "$a";
  if (content.args[0].name === "__number__" && (content.args[0].args[0].numValue < 0 || content.args[0].args[0].numValue > 360)) {
    error("Hue must be between 0 and 360", content.args[0].fileStack);
  }
  if (content.args[1].name === "__number__" && (content.args[1].args[0].numValue < 0 || content.args[1].args[0].numValue > 1)) {
    error("Saturation must be between 0 and 1", content.args[1].fileStack);
  }
  if (content.args[2].name === "__number__" && (content.args[2].args[0].numValue < 0 || content.args[2].args[0].numValue > 1)) {
    error("Lightness must be between 0 and 1", content.args[2].fileStack);
  }
  if (content.args[3].name === "__number__" && (content.args[3].args[0].numValue < 0 || content.args[3].args[0].numValue > 255)) {
    error("Alpha must be between 0 and 255", content.args[3].fileStack);
  }
  for (let arg of content.args) {
    if (astContainsRandom(arg)) {
      error("Cannot use random functions in hsl() or hsla()", arg.fileStack);
    }
  }
  let f = (n) => `(${l} - ${s}*min(${l}, 1-${l}) * max(min(min((${n}+${h}/30)%12 - 3, 9 - ((${n}+${h}/30)%12)), 1), -1))`;
  return parseOpyMacro(`rgba(${f(0)}*255, ${f(8)}*255, ${f(4)}*255, ${a})`, ["$h", "$s", "$l", "$a"], content.args);
};

// src/compiler/functions/hudText.ts
astParsingFunctions.hudText = function(content) {
  if (content.args[4].name === "ACTUALLY_LEFT") {
    if (content.args[2].name !== "null") {
      content.args[2] = getAstForCustomString("{}{}", [content.args[2], getAstForFucktonOfSpaces()]);
    } else if (content.args[3].name !== "null") {
      content.args[3] = getAstForCustomString("{}{}", [content.args[3], getAstForFucktonOfSpaces()]);
    } else {
      content.args[3] = getAstForFucktonOfSpaces();
    }
    content.args[4].name = "LEFT";
  }
  if (enableOptimization) {
    for (let i = 1; i <= 3; i++) {
      if (content.args[i].name === "__customString__" && content.args[i].args[0].name === "") {
        content.args[i] = getAstForNull();
      }
    }
    if (content.args[1].name === "null" && content.args[2].name === "null" && content.args[3].name === "null") {
      return getAstForUselessInstruction();
    }
    if (optimizeForSize2) {
      if (content.args[1].name === "null") {
        content.args[6] = getAstForNull();
      }
      if (content.args[2].name === "null") {
        content.args[7] = getAstForNull();
      }
      if (content.args[3].name === "null") {
        content.args[8] = getAstForNull();
      }
    }
  }
  return content;
};

// src/compiler/functions/len.ts
astParsingFunctions.len = function(content) {
  if (content.args[0].name === "__enumType__") {
    return getAstForNumber(content.args[0].args.length);
  } else if (enableOptimization) {
    if (content.args[0].name === "__array__") {
      return getAstForNumber(content.args[0].args.length);
    }
    if (content.args[0].name === "__emptyArray__") {
      return getAstFor0();
    }
    if (content.args[0].name === "getPlayers") {
      return new Ast2("getNumberOfPlayers", [content.args[0].args[0]]);
    }
    if (content.args[0].name === "getLivingPlayers") {
      return new Ast2("getNumberOfLivingPlayers", [content.args[0].args[0]]);
    }
    if (content.args[0].name === "getDeadPlayers") {
      return new Ast2("getNumberOfDeadPlayers", [content.args[0].args[0]]);
    }
    if (content.args[0].name === "getPlayersOnObjective") {
      return new Ast2("getNumberOfPlayersOnObjective", [content.args[0].args[0]]);
    }
    if (content.args[0].name === "getPlayersOnHero") {
      return new Ast2("getNumberOfHeroes", [content.args[0].args[0], content.args[0].args[1]]);
    }
  }
  return content;
};

// src/compiler/functions/log.ts
astParsingFunctions.log = function(content) {
  if (content.args[1].name === "__number__" && content.args[1].args[0].numValue === Math.E) {
    if (enableOptimization && content.args[0].name === "__number__") {
      return getAstForNumber(Math.log(content.args[0].args[0].numValue));
    }
    return parseOpyMacro(`10000 * ($nb1 ** 0.0001 - 1)`, ["$nb1"], content.args);
  } else {
    return parseOpyMacro(`log($nb1) / log($nb2)`, ["$nb1", "$nb2"], content.args);
  }
};

// src/compiler/functions/magnitude.ts
astParsingFunctions.magnitude = function(content) {
  if (enableOptimization) {
    if (content.args[0].name === "vect") {
      let [x, y, z] = content.args[0].args.map((arg) => numValue(arg));
      if ([x, y, z].every((num) => num !== null)) {
        return getAstForNumber(Math.sqrt(x ** 2 + y ** 2 + z ** 2));
      }
    }
  }
  return content;
};

// src/compiler/functions/max.ts
astParsingFunctions.max = function(content) {
  if (enableOptimization) {
    let numbers = content.args.filter((arg) => arg.name === "__number__").map((arg) => arg.args[0].numValue);
    if (numbers.length === content.args.length) {
      return getAstForNumber(Math.max(...numbers));
    }
    let maxNumber = Math.max(...numbers);
    content.args = content.args.filter((x) => x.name !== "__number__" || x.args[0].numValue === maxNumber);
  }
  if (content.args.length > 2) {
    return new Ast2("max", [content.args[0], astParsingFunctions.max(new Ast2("max", content.args.slice(1)))]);
  }
  return content;
};

// src/compiler/functions/min.ts
astParsingFunctions.min = function(content) {
  if (enableOptimization) {
    let numbers = content.args.filter((arg) => arg.name === "__number__").map((arg) => arg.args[0].numValue);
    if (numbers.length === content.args.length) {
      return getAstForNumber(Math.min(...numbers));
    }
    let minNumber = Math.min(...numbers);
    content.args = content.args.filter((x) => x.name !== "__number__" || x.args[0].numValue === minNumber);
  }
  if (content.args.length > 2) {
    return new Ast2("min", [content.args[0], astParsingFunctions.min(new Ast2("min", content.args.slice(1)))]);
  }
  return content;
};

// src/compiler/functions/normalize.ts
astParsingFunctions.normalize = function(content) {
  if (enableOptimization) {
    if (content.args[0].name === "vect") {
      let [x, y, z] = content.args[0].args.map((arg) => numValue(arg));
      if ([x, y, z].every((num) => num !== null)) {
        var magnitude = Math.sqrt(x ** 2 + y ** 2 + z ** 2);
        if (magnitude === 0) {
          return getAstForNullVector();
        }
        return getAstForVector(x / magnitude, y / magnitude, z / magnitude);
      }
    } else if (content.args[0].name === "vectorTowards") {
      return new Ast2("directionTowards", [content.args[0].args[0], content.args[0].args[1]]);
    }
  }
  return content;
};

// src/compiler/functions/playEffect.ts
astParsingFunctions.playEffect = function(content) {
  if (!(content.args[1].name in constantValues[content.args[1].type])) {
    error("Unknown dynamic effect '" + content.args[1].name + "'", content.args[1].fileStack);
  }
  if (constantValues[content.args[1].type][content.args[1].name].extension && !activatedExtensions.includes(constantValues[content.args[1].type][content.args[1].name].extension ?? error("Check for workshop extension while playing effect failed"))) {
    error("You must activate the extension '" + constantValues[content.args[1].type][content.args[1].name].extension + "' to use '" + content.args[1].type + "." + content.args[1].name + "'", content.args[1].fileStack);
  }
  return content;
};

